import React from "react";
import Sidebar from "./components/Sidebar";
import LoginBox from "./components/LoginBox"; // Import LoginBox
import { FaProjectDiagram } from "react-icons/fa"; // Importing an icon

const AppLayout = ({ children }) => {
  return (
    <div className="flex h-screen bg-gray-100">
      {/* Sidebar */}
      <aside className="w-50 bg-gray-900 text-white p-4">
        <Sidebar />
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col justify-center items-center">
        {/* Header */}
        <header className="bg-gradient-to-r from-purple-700 to-indigo-800 text-white py-6 px-8 shadow-lg w-full text-center flex flex-col items-center animate-fadeIn">
          <FaProjectDiagram className="text-5xl text-yellow-300 mb-2 animate-bounce" />
          <h1 className="text-2xl font-semibold tracking-wide">
            🚀 Manage Your Projects Efficiently With
          </h1>
          <h2 className="text-4xl font-extrabold text-yellow-300 mt-2">
            Proma
          </h2>
        </header>

        {/* Page Content */}
        <div className="p-6">{children}</div>

        {/* Login Box in Center */}
        <LoginBox />
      </main>
    </div>
  );
};

export default AppLayout;
